+/// use asupersync::types::Time;
+///
+/// let sleep_future = sleep_until(Time::from_secs(5));
+/// assert_eq!(sleep_future.deadline(), Time::from_secs(5));
+/// ```
+#[must_use]
+pub const fn sleep_until(deadline: Time) -> Sleep {
+    Sleep::new(deadline)
+}
